VALUES
  ('police-b20a8cf8-moex-00024', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '比較憲法第43條關於緊急命令與憲法增修條文第2條第3項關於緊急命令之要件與程序， 下列敘述何者錯誤？', '["發布事由中之「國家遇有天然災害、癘疫」，改成「為避免國家或人民遭受緊急危難」", "發布依據從必須「依緊急命令法發布緊急命令」，改成得不必依緊急命令法就可以發布", "追認時間從「發布命令後1個月內提交立法院追認」，改成「發布命令後10日內提交立 法院追認」", "從原本之「立法院休會期間，經行政院會議決議，得發布緊急命令」，改成無論是否在立 法院休會期間，均無須經行政院會議決議，總統即可發布緊急命令"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00025', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依據權力分立原則並參照憲法增修條文相關規定，行政院應受立法院之監督，下列敘述何者 錯誤？', '["行政院必須向立法院提出施政方針及施政報告", "總統提名行政院院長後必須經立法院同意", "立法院得經全體立法委員3分之1以上連署，對行政院院長提出不信任案", "行政院移請立法院覆議案，經全體立法委員2分之1以上決議維持原案者，行政院院長應 接受該決議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00026', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '關於議會議員之地位及職權，下列敘述何者最為正確？', '["現代代議民主國家多採自由委任制，即代議士為選區選民所派遣，受到選區選民指令的 拘束", "以區域選舉產生之各級民意代表得為原選舉區選民所罷免，故非純粹的自由委任制", "憲法明文規定立法委員及地方議員均享有言論免責權", "立法委員於會期中及休會期間，皆享有不受逮捕拘禁之特權；而地方議員之此項特權，僅 限於會期內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00027', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依憲法與增修條文之現行規定，有關公務人員選拔，下列敘述何者正確？', '["公務人員之選拔，應以實作方式考選，以確保任用優秀人才", "公務人員之選拔，應按省（直轄市）分定名額，分區考試", "公務人員之選拔，應經公開考試，方得任用", "公務人員之選拔，應依年齡分布，任用一定比例之青年 51250、51350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00028', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '關於審計長，下列敘述何者正確？', '["由總統逕自任命之", "不受任期保障", "應於行政院提出決算後於期限內完成審核，並提出審核報告於立法院", "立法院委員會審議決算報告時，有至立法院備詢之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00029', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依憲法訴訟法規定，有關法庭之友之敘述，下列何者正確？', '["法庭之友制度，乃沿用司法院大法官審理案件法中已存之制度", "案件之關聯性，應包含情感上的關聯性", "依裁定許可提出專業意見或資料時，無需揭露與當事人間之關係", "人民向憲法法庭聲請擔任法庭之友時，應委任代理人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00030', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '關於訴訟權的限制，下列敘述何者錯誤？', '["不得以經濟利益，限制上訴", "不得以身分，限制訴訟權之行使", "得設再審不變期間之限制", "得設上訴期間之限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00031', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依憲法及相關法律規定，關於國家賠償，下列敘述何者正確？', '["國家賠償乃是基於填補人民之特別犧牲而生的責任", "國家補償係針對國家無過失造成的損害，國家賠償則僅限於國家有過失所造成之損害", "憲法第 24 條關於公務員違法導致損害應負賠償責任，未規定以故意過失為要件，故屬於 無過失責任", "國家對公務員之求償，限於具故意或重大過失之情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00032', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '特別公課是指國家為一定政策目標之需要，對於有特定關係之國民所課徵之公法上負擔，將 課徵所得之金錢，以建立特別基金，專供特定目標達成，有專款專用之意旨。依上述說明， 下列何者屬於特別公課？', '["空氣污染防制費", "貨物稅", "全民健康保險費", "國家考試報名費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00033', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '有關一般行為自由之保障範圍，不包括下列何者？', '["與非配偶從事性行為之性自主權", "人民隨時任意前往他方或停留一定處所之行動自由", "一般人民駕駛汽車之自由", "人民依其意志作為或不作為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
